import React from 'react';
import { useNavigate } from 'react-router-dom';

const TopProductsTable = ({ data }) => {
  const navigate = useNavigate();

  // ✅ Проверяем, что data и data.top_products существуют
  if (!data || !data.top_products) return <div>Нет данных</div>;

  return (
    <div className="overflow-x-auto">
      <table className="min-w-full bg-white dark:bg-gray-800 rounded-lg overflow-hidden">
        <thead className="bg-gray-100 dark:bg-gray-700">
          <tr>
            <th className="py-2 px-4 text-left">SKU</th>
            <th className="py-2 px-4 text-left">Название</th>
            <th className="py-2 px-4 text-left">Выручка</th>
            <th className="py-2 px-4 text-left">Остаток</th>
            <th className="py-2 px-4 text-left">Логистика</th>
          </tr>
        </thead>
        <tbody>
          {data.top_products.map((product) => (
            <tr
              key={product.sku}
              className="hover:bg-gray-50 dark:hover:bg-gray-700 cursor-pointer"
              onClick={() => navigate(`/product/${product.sku}`)}
            >
              <td className="py-2 px-4 border-t dark:border-gray-700">{product.sku}</td>
              <td className="py-2 px-4 border-t dark:border-gray-700">{product.name}</td>
              <td className="py-2 px-4 border-t dark:border-gray-700">{product.revenue.toLocaleString()} ₽</td>
              <td className="py-2 px-4 border-t dark:border-gray-700">{product.stock}</td>
              <td className="py-2 px-4 border-t dark:border-gray-700">
                <span
                  className={`px-2 py-1 rounded-full text-xs ${
                    product.logistics === 'FBO' ? 'bg-green-100 text-green-800' : 'bg-blue-100 text-blue-800'
                  }`}
                >
                  {product.logistics}
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default TopProductsTable;
